SELECT count(*) FROM title, kind_type, movie_companies, cast_info, company_type, movie_info, company_name, movie_keyword, info_type WHERE title.kind_id = kind_type.id AND movie_companies.movie_id = title.id AND cast_info.movie_id = title.id AND movie_companies.company_type_id = company_type.id AND movie_info.movie_id = title.id AND movie_companies.company_id = company_name.id AND movie_keyword.movie_id = title.id AND movie_info.info_type_id = info_type.id;